import java.io.*;
import java.util.*;

public class Main {
    private static int gcd(int a, int b) {
        while (b != 0) {
            int t = b;
            b = a % b;
            a = t;
        }
        return a;
    }

    public static void main(String[] args) throws Exception {
        // Read the whole input as a raw string (may contain escaped "\\n")
        String data = new String(System.in.readAllBytes());
        // Convert escaped newlines to spaces and also normalize real newlines
        data = data.replace("\\n", " ");
        data = data.replace('\n', ' ');
        data = data.replace('\r', ' ');
        StringTokenizer st = new StringTokenizer(data);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = Integer.parseInt(st.nextToken());
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = Integer.parseInt(st.nextToken());
            }
            if (n == 1) {
                sb.append(0).append('\n');
                continue;
            }
            int[] pre = new int[n];
            int[] suf = new int[n];
            for (int i = 0; i < n; i++) {
                pre[i] = (i == 0) ? a[i] : gcd(pre[i - 1], a[i]);
            }
            for (int i = n - 1; i >= 0; i--) {
                suf[i] = (i == n - 1) ? a[i] : gcd(suf[i + 1], a[i]);
            }
            int ans = 0;
            for (int i = 0; i < n; i++) {
                int cur;
                if (i == 0) {
                    cur = suf[1];
                } else if (i == n - 1) {
                    cur = pre[n - 2];
                } else {
                    cur = gcd(pre[i - 1], suf[i + 1]);
                }
                if (cur > ans) ans = cur;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

